#include <unordered_map>
#include <string>

class FoodRatings {
public:
    FoodRatings(vector<string>& foods, vector<string>& cuisines, vector<int>& ratings) {
        // Initialize a map to store food items and their ratings
        unordered_map<string, int> foodMap;
        for (int i = 0; i < foods.size(); i++) {
            foodMap[foods[i]] = ratings[i];
        }
    }

    void changeRating(string food, int newRating) {
        // Update the rating of the food item in the map
        foodMap[food] = newRating;
    }

    string highestRated(string cuisine) {
        // Find the highest rated food item for the given cuisine
        string highestRatedFood = "";
        for (auto it = foodMap.begin(); it != foodMap.end(); it++) {
            if (it->second > highestRatedFood) {
                highestRatedFood = it->first;
            }
        }
        return highestRatedFood;
    }
};

```

